import { useState } from "react";
import { useSelector, useDispatch } from "react-redux";
import { useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import bcrypt from "bcryptjs";
import { login } from "../authReducer";

function Register() {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("student");
  const [classId, setClassId] = useState("");
  const [avatarFile, setAvatarFile] = useState(null);
  const [classes, setClasses] = useState([]);
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  useState(() => {
    fetch("http://localhost:3001/classes")
      .then((res) => res.json())
      .then((data) => setClasses(data))
      .catch((error) => toast.error("Ошибка загрузки классов"));
  }, []);

  if (user) {
    navigate("/dashboard");
    return null;
  }

  async function handleSubmit(e) {
    e.preventDefault();
    try {
      const emailResponse = await fetch(
        `http://localhost:3001/users?email=${email}`
      );
      const existingUsers = await emailResponse.json();
      if (existingUsers.length > 0) {
        toast.error("Пользователь с таким email уже существует");
        return;
      }

      let avatarPath = null;
      if (avatarFile) {
        const allowedTypes = ["image/jpeg", "image/png"];
        const maxSize = 2 * 1024 * 1024;

        if (!allowedTypes.includes(avatarFile.type)) {
          toast.error("Допустимы только изображения (JPEG, PNG)");
          return;
        }

        if (avatarFile.size > maxSize) {
          toast.error("Файл слишком большой. Максимальный размер: 2 МБ");
          return;
        }

        const formData = new FormData();
        formData.append("file", avatarFile);
        const uploadResponse = await fetch("http://localhost:3002/upload", {
          method: "POST",
          body: formData,
        });
        const uploadData = await uploadResponse.json();
        if (uploadResponse.ok) {
          avatarPath = uploadData.filePath;
        } else {
          toast.error("Не удалось загрузить аватар");
          return;
        }
      }

      const hashedPassword = await bcrypt.hash(password, 10);
      const newUser = {
        name,
        email,
        password: hashedPassword,
        role,
        classId: role === "student" ? parseInt(classId) : null,
        avatar: avatarPath,
        isBanned: false,
      };

      const response = await fetch("http://localhost:3001/users", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newUser),
      });

      if (response.ok) {
        const createdUser = await response.json();
        dispatch(login(createdUser));
        await fetch("http://localhost:3001/notifications", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            userId: createdUser.id,
            message: `Добро пожаловать, ${name}! Вы успешно зарегистрированы.`,
            createdAt: new Date().toISOString(),
          }),
        });
        toast.success("Регистрация успешна!");
        navigate("/dashboard");
      } else {
        toast.error("Не удалось зарегистрироваться");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при регистрации");
    }
  }

  return (
    <div className="container mt-5">
      <div className="row justify-content-center">
        <div className="col-md-6">
          <div className="card shadow">
            <div className="card-body">
              <h2 className="card-title text-center mb-4">Регистрация</h2>
              <form onSubmit={handleSubmit}>
                <div className="mb-3">
                  <label htmlFor="name" className="form-label">
                    Имя
                  </label>
                  <input
                    type="text"
                    id="name"
                    className="form-control"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="email" className="form-label">
                    Email
                  </label>
                  <input
                    type="email"
                    id="email"
                    className="form-control"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="password" className="form-label">
                    Пароль
                  </label>
                  <input
                    type="password"
                    id="password"
                    className="form-control"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="role" className="form-label">
                    Роль
                  </label>
                  <select
                    id="role"
                    className="form-select"
                    value={role}
                    onChange={(e) => setRole(e.target.value)}
                    required
                  >
                    <option value="student">Студент</option>
                    <option value="teacher">Учитель</option>
                    <option value="admin">Администратор</option>
                  </select>
                </div>
                {role === "student" && (
                  <div className="mb-3">
                    <label htmlFor="classId" className="form-label">
                      Класс
                    </label>
                    <select
                      id="classId"
                      className="form-select"
                      value={classId}
                      onChange={(e) => setClassId(e.target.value)}
                      required
                    >
                      <option value="">-- Выберите класс --</option>
                      {classes.map((cls) => (
                        <option key={cls.id} value={cls.id}>
                          {cls.name}
                        </option>
                      ))}
                    </select>
                  </div>
                )}
                <div className="mb-3">
                  <label htmlFor="avatar" className="form-label">
                    Аватар (опционально, JPEG/PNG, до 2 МБ)
                  </label>
                  <input
                    type="file"
                    id="avatar"
                    className="form-control"
                    onChange={(e) => setAvatarFile(e.target.files[0])}
                  />
                </div>
                <button type="submit" className="btn btn-primary w-100">
                  Зарегистрироваться
                </button>
              </form>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Register;
